import{_ as t,o as e,c as r,a2 as l}from"./chunks/framework.Cd7uensT.js";const c=JSON.parse('{"title":"耗材管理","description":"","frontmatter":{},"headers":[],"relativePath":"guide/features/consumable-management.md","filePath":"guide/features/consumable-management.md","lastUpdated":1781596792000}'),o={name:"guide/features/consumable-management.md"};function i(n,a,s,d,h,u){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="耗材管理" tabindex="-1">耗材管理 <a class="header-anchor" href="#耗材管理" aria-label="Permalink to &quot;耗材管理&quot;">​</a></h1><h2 id="耗材统计" tabindex="-1">耗材统计 <a class="header-anchor" href="#耗材统计" aria-label="Permalink to &quot;耗材统计&quot;">​</a></h2><p>提供库存数据的可视化分析，包括：库存总览、分类统计、库存预警、领用趋势。</p><h2 id="耗材列表" tabindex="-1">耗材列表 <a class="header-anchor" href="#耗材列表" aria-label="Permalink to &quot;耗材列表&quot;">​</a></h2><h3 id="新增耗材" tabindex="-1">新增耗材 <a class="header-anchor" href="#新增耗材" aria-label="Permalink to &quot;新增耗材&quot;">​</a></h3><ol><li>进入「耗材列表」页面</li><li>点击「新增耗材」</li><li>填写耗材信息：名称、分类、规格、计量单位、库存数量、安全库存等</li><li>保存</li></ol><h3 id="库存操作" tabindex="-1">库存操作 <a class="header-anchor" href="#库存操作" aria-label="Permalink to &quot;库存操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><strong>入库</strong></td><td>增加库存数量</td></tr><tr><td><strong>出库/领用</strong></td><td>减少库存数量，记录领用人</td></tr><tr><td><strong>盘点</strong></td><td>更新实际库存数量</td></tr></tbody></table><h3 id="sn-序列号追踪" tabindex="-1">SN 序列号追踪 <a class="header-anchor" href="#sn-序列号追踪" aria-label="Permalink to &quot;SN 序列号追踪&quot;">​</a></h3><p>对于需要精确管理的耗材（如硬盘、内存模块等），支持 SN 序列号级别的追踪管理：</p><ul><li><strong>SN 录入</strong>：入库时逐个输入或批量扫描耗材的 SN 序列号</li><li><strong>SN 追溯</strong>：在耗材详情页可查看每个 SN 序列号的完整流转记录（入库时间、使用去向、当前状态等）</li><li><strong>SN 出库</strong>：出库/领用时扫描具体 SN，确保实物与系统记录一致</li><li><strong>SN 状态标识</strong>： <ul><li>🟢 在库：序列号对应的耗材在库存中</li><li>🟡 已领用：序列号对应的耗材已出库分配给指定人员</li><li>🔴 已报废：序列号对应的耗材已报废处理</li></ul></li></ul><h3 id="版本号乐观锁" tabindex="-1">版本号乐观锁 <a class="header-anchor" href="#版本号乐观锁" aria-label="Permalink to &quot;版本号乐观锁&quot;">​</a></h3><p>耗材模块采用乐观锁机制确保并发操作下的数据一致性：</p><ul><li><strong>实现方式</strong>：每条耗材记录维护一个版本号（version 字段）</li><li><strong>更新校验</strong>：执行入库、出库、盘点等操作时，系统校验当前版本号与操作发起时的版本号是否一致</li><li><strong>冲突处理</strong>：若版本号不一致（表示有其他用户同时修改了该记录），系统提示&quot;数据已被其他操作修改，请刷新后重试&quot;</li><li><strong>适用范围</strong>：所有修改库存数量的操作均受乐观锁保护，避免多用户同时操作导致的库存数量不一致问题</li></ul><h2 id="分类管理" tabindex="-1">分类管理 <a class="header-anchor" href="#分类管理" aria-label="Permalink to &quot;分类管理&quot;">​</a></h2><p>分类管理用于维护耗材的分类体系，支持多级分类。</p><h2 id="操作日志" tabindex="-1">操作日志 <a class="header-anchor" href="#操作日志" aria-label="Permalink to &quot;操作日志&quot;">​</a></h2><p>记录所有耗材的出入库操作历史，支持按时间范围、耗材名称、操作类型筛选查询。</p><h3 id="日志归档" tabindex="-1">日志归档 <a class="header-anchor" href="#日志归档" aria-label="Permalink to &quot;日志归档&quot;">​</a></h3><p>操作日志支持自动归档机制，以保障系统性能和满足合规要求：</p><ul><li><strong>归档策略</strong>：系统默认保留近 12 个月的操作日志，超出部分自动归档</li><li><strong>归档存储</strong>：归档日志以压缩格式存储，支持导出为 Excel/CSV 文件本地保存</li><li><strong>归档查询</strong>：归档后的日志仍可在系统中查询，但加载速度低于实时日志</li><li><strong>手动归档</strong>：管理员可随时手动触发归档操作，并指定归档的时间范围</li><li><strong>归档清理</strong>：归档超过 36 个月的日志系统自动清理，释放存储空间</li></ul>',21)])])}const m=t(o,[["render",i]]);export{c as __pageData,m as default};
